const input = $input.first().json;
const action = input.action || '';

const API = 'https://openlibrary.org';
const COVERS = 'https://covers.openlibrary.org';

function descToString(d) {
  if (!d) return '';
  if (typeof d === 'string') return d;
  if (typeof d === 'object' && d.value) return d.value;
  return '';
}

function truncate(s, n) {
  if (!s) return '';
  s = String(s);
  if (s.length <= n) return s;
  return s.substring(0, n) + '...';
}

function normalizeWorkKey(k) {
  if (!k) return '';
  k = String(k).trim();
  if (k.startsWith('/works/')) return k;
  if (k.startsWith('OL') && k.endsWith('W')) return '/works/' + k;
  return k.startsWith('/') ? k : '/works/' + k;
}

function normalizeAuthorKey(k) {
  if (!k) return '';
  k = String(k).trim();
  if (k.startsWith('/authors/')) return k;
  if (k.startsWith('OL') && k.endsWith('A')) return '/authors/' + k;
  return k.startsWith('/') ? k : '/authors/' + k;
}

// === search_books ===
if (action === 'search_books') {
  const query = input.query;
  if (!query) {
    return [{ json: { error: 'Parameter "query" is required. Examples: "Harry Potter", "author:murakami", "isbn:9780747532743".' } }];
  }
  const limit = Math.min(parseInt(input.limit) || 5, 20);
  const sort = input.sort || 'relevance';
  const validSorts = ['relevance', 'new', 'old', 'rating', 'readinglog', 'editions'];
  const sortParam = validSorts.includes(sort) ? sort : 'relevance';

  try {
    const fields = 'key,title,author_name,first_publish_year,edition_count,cover_i,ratings_average,isbn,language';
    let url = API + '/search.json?q=' + encodeURIComponent(query) + '&limit=' + limit + '&fields=' + fields;
    if (sortParam !== 'relevance') url += '&sort=' + sortParam;

    const data = await helpers.httpRequest({ method: 'GET', url });
    const docs = data.docs || [];

    if (docs.length === 0) {
      return [{ json: { result: 'No books found for: ' + query } }];
    }

    let result = 'Found ' + data.numFound + ' books, showing top ' + docs.length + ':\n\n';
    for (const b of docs) {
      const authors = (b.author_name || []).slice(0, 3).join(', ');
      result += '**' + b.title + '**';
      if (authors) result += ' — ' + authors;
      result += '\n';
      if (b.first_publish_year) result += '  First published: ' + b.first_publish_year + '\n';
      if (b.edition_count) result += '  Editions: ' + b.edition_count + '\n';
      if (b.ratings_average) result += '  Rating: ' + b.ratings_average.toFixed(2) + '/5\n';
      if (b.cover_i) result += '  Cover: ' + COVERS + '/b/id/' + b.cover_i + '-M.jpg\n';
      if (b.key) result += '  Work key: ' + b.key + '\n';
      result += '\n';
    }
    if (result.length > 5000) result = result.substring(0, 5000) + '\n... (truncated)';
    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Search failed: ' + err.message } }];
  }

// === get_book ===
} else if (action === 'get_book') {
  const workKey = input.work_key;
  const isbn = input.isbn;
  if (!workKey && !isbn) {
    return [{ json: { error: 'Either "work_key" (e.g. OL27448W or /works/OL27448W) or "isbn" is required.' } }];
  }

  try {
    let workData;
    let resolvedKey;

    if (isbn) {
      const cleanIsbn = String(isbn).replace(/[-\s]/g, '');
      const isbnData = await helpers.httpRequest({ method: 'GET', url: API + '/isbn/' + encodeURIComponent(cleanIsbn) + '.json' });
      if (isbnData.works && isbnData.works[0] && isbnData.works[0].key) {
        resolvedKey = isbnData.works[0].key;
        workData = await helpers.httpRequest({ method: 'GET', url: API + resolvedKey + '.json' });
      } else {
        let result = '**' + isbnData.title + '** (edition info, ISBN ' + cleanIsbn + ')\n';
        if (isbnData.publish_date) result += 'Published: ' + isbnData.publish_date + '\n';
        if (isbnData.publishers) result += 'Publisher: ' + isbnData.publishers.join(', ') + '\n';
        if (isbnData.number_of_pages) result += 'Pages: ' + isbnData.number_of_pages + '\n';
        return [{ json: { result } }];
      }
    } else {
      resolvedKey = normalizeWorkKey(workKey);
      workData = await helpers.httpRequest({ method: 'GET', url: API + resolvedKey + '.json' });
    }

    let result = '**' + workData.title + '**\n';
    result += 'Work key: ' + resolvedKey + '\n';

    if (workData.authors && workData.authors.length > 0) {
      const authorNames = [];
      for (const a of workData.authors.slice(0, 3)) {
        const aKey = a.author && a.author.key;
        if (aKey) {
          try {
            const aData = await helpers.httpRequest({ method: 'GET', url: API + aKey + '.json' });
            authorNames.push(aData.name + ' (' + aKey + ')');
          } catch (e) {
            authorNames.push(aKey);
          }
        }
      }
      if (authorNames.length > 0) result += 'Author(s): ' + authorNames.join(', ') + '\n';
    }

    if (workData.first_publish_date) result += 'First published: ' + workData.first_publish_date + '\n';

    if (workData.covers && workData.covers[0]) {
      result += 'Cover: ' + COVERS + '/b/id/' + workData.covers[0] + '-L.jpg\n';
    }

    const desc = descToString(workData.description);
    if (desc) result += '\nDescription:\n' + truncate(desc, 2000) + '\n';

    if (workData.subjects && workData.subjects.length > 0) {
      result += '\nSubjects: ' + workData.subjects.slice(0, 10).join(', ') + '\n';
    }

    if (result.length > 5000) result = result.substring(0, 5000) + '\n... (truncated)';
    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to get book: ' + err.message } }];
  }

// === get_author ===
} else if (action === 'get_author') {
  const authorKey = input.author_key;
  const name = input.name;
  if (!authorKey && !name) {
    return [{ json: { error: 'Either "author_key" (e.g. OL30351A) or "name" is required.' } }];
  }

  try {
    let resolvedKey;

    if (authorKey) {
      resolvedKey = normalizeAuthorKey(authorKey);
    } else {
      const sData = await helpers.httpRequest({
        method: 'GET',
        url: API + '/search/authors.json?q=' + encodeURIComponent(name) + '&limit=1'
      });
      if (!sData.docs || sData.docs.length === 0) {
        return [{ json: { result: 'No author found for: ' + name } }];
      }
      resolvedKey = '/authors/' + sData.docs[0].key;
    }

    const aData = await helpers.httpRequest({ method: 'GET', url: API + resolvedKey + '.json' });

    let result = '**' + (aData.name || 'Unknown') + '**\n';
    result += 'Author key: ' + resolvedKey + '\n';
    if (aData.birth_date) result += 'Born: ' + aData.birth_date + '\n';
    if (aData.death_date) result += 'Died: ' + aData.death_date + '\n';
    if (aData.alternate_names && aData.alternate_names.length > 0) {
      result += 'Also known as: ' + aData.alternate_names.slice(0, 5).join(', ') + '\n';
    }
    const bio = descToString(aData.bio);
    if (bio) result += '\nBio:\n' + truncate(bio, 1500) + '\n';

    try {
      const works = await helpers.httpRequest({
        method: 'GET',
        url: API + resolvedKey + '/works.json?limit=10'
      });
      if (works.entries && works.entries.length > 0) {
        result += '\nWorks (' + (works.size || works.entries.length) + ' total, showing ' + works.entries.length + '):\n';
        for (const w of works.entries) {
          result += '- ' + w.title + ' (' + w.key + ')\n';
        }
      }
    } catch (e) {
      // ignore works fetch errors
    }

    if (result.length > 5000) result = result.substring(0, 5000) + '\n... (truncated)';
    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to get author: ' + err.message } }];
  }

} else {
  return [{ json: { error: 'Unknown action: "' + action + '". Available: search_books, get_book, get_author.' } }];
}
